+/// Safe division for f64 numerator with i64 denominator.
+/// Returns `None` when the denominator is zero.
+pub fn safe_div_f64(numerator: f64, denominator: i64) -> Option<f64> {
+    if denominator == 0 {
+        None
+    } else {
+        Some(numerator / denominator as f64)
+    }
+}
